#include <iostream>
int produit(int a, int b) {
    return a * b;
}
int main() {
    std::cout << produit(6, 7) << std::endl;
    return 0;
}

#include <iostream>
#include <vector>
int main() {
    std::vector<int> v = {3, 6, 9};
    for (int x : v) std::cout << x << std::endl;
    return 0;
}

#include <iostream>
#include <vector>
int main() {
    std::vector<int> v = {2, 4, 6, 8};
    int total = 0;
    for (int x : v) total += x;
    std::cout << total << std::endl;
    return 0;
}
